<script setup lang="ts">
/**
 * 通用 Modal 弹窗:
 * - Teleport 到 body,避免父容器 z-index/overflow 干扰
 * - 半透明黑色 backdrop,点击关闭
 * - ESC 键关闭
 * - 打开时锁 body 滚动,关闭时还原
 * - v-model 双向绑定
 */
import { onBeforeUnmount, watch } from 'vue'

const props = withDefaults(
  defineProps<{
    modelValue: boolean
    width?: string
    /** 是否允许点击 backdrop 关闭(默认 true) */
    closeOnBackdrop?: boolean
  }>(),
  { width: '720px', closeOnBackdrop: true },
)

const emit = defineEmits<{
  'update:modelValue': [v: boolean]
  close: []
}>()

function close() {
  emit('update:modelValue', false)
  emit('close')
}

function onKeydown(e: KeyboardEvent) {
  if (e.key === 'Escape' && props.modelValue) close()
}

function onBackdrop() {
  if (props.closeOnBackdrop) close()
}

watch(
  () => props.modelValue,
  (v) => {
    if (typeof document === 'undefined') return
    document.body.style.overflow = v ? 'hidden' : ''
  },
  { immediate: true },
)

if (typeof window !== 'undefined') {
  window.addEventListener('keydown', onKeydown)
  onBeforeUnmount(() => {
    window.removeEventListener('keydown', onKeydown)
    if (typeof document !== 'undefined') document.body.style.overflow = ''
  })
}
</script>

<template>
  <Teleport to="body">
    <div
      v-if="modelValue"
      class="fixed inset-0 z-[80] flex items-center justify-center p-4"
      role="dialog"
      aria-modal="true"
    >
      <!-- backdrop -->
      <div class="absolute inset-0 bg-black/65 backdrop-blur-[2px]" @click="onBackdrop" />
      <!-- 内容卡片:点击自身不冒泡 -->
      <div
        class="relative max-h-[95vh] overflow-auto rounded-xl shadow-2xl"
        :style="{ width }"
        @click.stop
      >
        <slot />
      </div>
    </div>
  </Teleport>
</template>
