/**
 * 角色信息面板的开关状态(单例)
 * 主页弹窗触发打开;任何地方(右上 ✕ / ESC / backdrop)都调 close
 * 由于是模块级 ref,Home 和 RolePage 调同一个 useRolePanel 时共享状态
 */
import { ref } from 'vue';
const isOpen = ref(false);
export function useRolePanel() {
    return {
        isOpen,
        open: () => {
            isOpen.value = true;
        },
        close: () => {
            isOpen.value = false;
        },
        toggle: () => {
            isOpen.value = !isOpen.value;
        },
    };
}
